172→// convertDate converts a BigFuture date string (MM/DD/9999) to YYYY-MM-DD
173→// using the given year. Returns empty string for null, empty, or unparseable dates.
174→func convertDate(s string, year int) string {
175→	s = strings.TrimSpace(s)
176→	if s == "" || s == "null" {
177→		return ""
178→	}
179→
180→	// Expected format: MM/DD/YYYY (where YYYY is often 9999).
181→	parts := strings.Split(s, "/")
182→	if len(parts) != 3 {
183→		return ""
184→	}
185→
186→	month := parts[0]
187→	day := parts[1]
188→
189→	// Validate month and day are numeric and in range.
190→	if len(month) < 1 || len(month) > 2 || len(day) < 1 || len(day) > 2 {
191→		return ""
192→	}
193→
194→	return fmt.Sprintf("%04d-%s-%s", year, zeroPad(month), zeroPad(day))
195→}
196→
197→// zeroPad ensures a 1-2 digit string is zero-padded to 2 digits.
198→func zeroPad(s string) string {
199→	if len(s) == 1 {
200→		return "0" + s
201→	}
202→	return s
203→}
204→
205→// slugFromOrgID is a fallback slug builder when we only have IDs, not a name.
206→func slugFromOrgID(orgID, diCode string) string {
207→	if orgID != "" {
208→		return orgID
209→	}
210→	return diCode
211→}
212→
213→var slugReplacer = regexp.MustCompile(`[^a-z0-9]+`)
214→
215→// SlugFromName converts an institution name to a BigFuture-style kebab-case slug.
216→func SlugFromName(name string) string {
217→	// Lowercase.
218→	s := strings.ToLower(name)
219→
220→	// Remove apostrophes and periods (BigFuture strips these rather than
221→	// replacing with hyphens).
222→	s = strings.NewReplacer("'", "", "'", "", ".", "").Replace(s)
223→
224→	// Replace any run of non-alphanumeric characters with a single hyphen.
225→	s = slugReplacer.ReplaceAllString(s, "-")
226→
227→	// Trim leading/trailing hyphens.
228→	s = strings.Trim(s, "-")
229→
230→	// Strip any remaining non-ASCII (safety net).
231→	s = strings.Map(func(r rune) rune {
232→		if r > unicode.MaxASCII {
233→			return -1
234→		}
235→		return r
236→	}, s)
237→
238→	return s
239→}
