 95→// parsePlatformFilter converts a comma-separated string of platform keys into
 96→// a set. An empty string means "all platforms".
 97→func parsePlatformFilter(s string) map[string]bool {
 98→	s = strings.TrimSpace(s)
 99→	if s == "" {
100→		return nil
101→	}
102→	m := make(map[string]bool)
103→	for _, k := range strings.Split(s, ",") {
104→		k = strings.TrimSpace(k)
105→		if k != "" {
106→			m[k] = true
107→		}
108→	}
109→	return m
110→}
111→
112→// scrapeAll runs each extractor (checking cache first) and returns a map of
113→// platform key → institution names. Errors from individual extractors are
114→// collected and returned separately.
115→func scrapeAll(ctx context.Context, extractors []platform.Extractor, browser *scraper.Browser, cache *scraper.Cache, filter map[string]bool) (map[string][]string, []error) {
116→	result := make(map[string][]string)
117→	var errs []error
118→
119→	for _, ext := range extractors {
120→		key := ext.Key()
121→		if filter != nil && !filter[key] {
122→			slog.Debug("admissions: skipping platform (filtered)", "platform", key)
123→			continue
124→		}
125→
126→		names, err := loadOrScrape(ctx, ext, browser, cache)
127→		if err != nil {
128→			slog.Warn("admissions: extractor failed", "platform", key, "error", err)
129→			errs = append(errs, fmt.Errorf("%s: %w", key, err))
130→			continue
131→		}
132→
133→		result[key] = names
134→		slog.Info("admissions: scraped", "platform", key, "institutions", len(names))
135→	}
136→
137→	return result, errs
138→}
139→
140→// loadOrScrape attempts to load cached results; on miss or stale, runs the
141→// extractor and saves the result to cache.
142→func loadOrScrape(ctx context.Context, ext platform.Extractor, browser *scraper.Browser, cache *scraper.Cache) ([]string, error) {
143→	names, err := cache.Load(ext.Key())
144→	if err == nil {
145→		slog.Debug("admissions: cache hit", "platform", ext.Key(), "institutions", len(names))
146→		return names, nil
147→	}
148→
149→	names, err = ext.Extract(ctx, browser)
150→	if err != nil {
151→		return nil, err
152→	}
153→
154→	if saveErr := cache.Save(ext.Key(), names); saveErr != nil {
155→		slog.Warn("admissions: cache save failed", "platform", ext.Key(), "error", saveErr)
156→	}
157→
158→	return names, nil
159→}
