161→// platformStat tracks scrape/match statistics for a single platform.
162→type platformStat struct {
163→	key       string
164→	scraped   int
165→	matched   int
166→	unmatched int
167→}
168→
169→// aggregateAdmissions matches institution names from each platform to unit IDs
170→// and builds a map of unitID → sorted platform keys.
171→func aggregateAdmissions(platformNames map[string][]string, matcher *namematch.Matcher) (map[string][]string, []platformStat) {
172→	byUnit := make(map[string]map[string]bool)
173→	var stats []platformStat
174→
175→	// Process platforms in sorted order for deterministic output.
176→	keys := make([]string, 0, len(platformNames))
177→	for k := range platformNames {
178→		keys = append(keys, k)
179→	}
180→	sort.Strings(keys)
181→
182→	for _, key := range keys {
183→		names := platformNames[key]
184→		s := platformStat{key: key, scraped: len(names)}
185→
186→		for _, name := range names {
187→			unitID, ok := matcher.Match(name)
188→			if !ok {
189→				s.unmatched++
190→				slog.Debug("admissions: unmatched", "platform", key, "name", name)
191→				continue
192→			}
193→			s.matched++
194→			if byUnit[unitID] == nil {
195→				byUnit[unitID] = make(map[string]bool)
196→			}
197→			byUnit[unitID][key] = true
198→		}
199→		stats = append(stats, s)
200→	}
201→
202→	// Convert sets to sorted slices.
203→	result := make(map[string][]string, len(byUnit))
204→	for unitID, keySet := range byUnit {
205→		sorted := make([]string, 0, len(keySet))
206→		for k := range keySet {
207→			sorted = append(sorted, k)
208→		}
209→		sort.Strings(sorted)
210→		result[unitID] = sorted
211→	}
212→
213→	return result, stats
214→}
215→
216→// admissionsPayload is the JSON structure stored in the admissions column.
217→type admissionsPayload struct {
218→	Applications []string `json:"applications"`
219→}
220→
221→// buildAdmissionsJSON converts the aggregated map into serialized JSON
222→// suitable for BulkSetAdmissions.
223→func buildAdmissionsJSON(admissions map[string][]string) (map[string][]byte, error) {
224→	result := make(map[string][]byte, len(admissions))
225→	for unitID, platforms := range admissions {
226→		payload := admissionsPayload{Applications: platforms}
227→		data, err := json.Marshal(payload)
228→		if err != nil {
229→			return nil, fmt.Errorf("marshal %s: %w", unitID, err)
230→		}
231→		result[unitID] = data
232→	}
233→	return result, nil
234→}
